class Solution:
    def complexNumberMultiply(self, num1: str, num2: str) -> str:
        def parse(s):
            i = s.index('+')
            a = int(s[:i])
            b = int(s[i+1:-1])
            return a, b
        a, b = parse(num1)
        c, d = parse(num2)
        return f"{a*c-b*d}+{a*d+b*c}i"

